@function color-contrast($color1, $color2) {
  // Adapted from: https://github.com/LeaVerou/contrast-ratio/blob/gh-pages/color.js
  // Formula: http://www.w3.org/TR/2008/REC-WCAG20-20081211/#contrast-ratiodef
  $luminance1: color-luminance($color1) + 0.05;
  $luminance2: color-luminance($color2) + 0.05;
  $ratio: divide($luminance1, $luminance2);

  @if $luminance2 > $luminance1 {
    $ratio: divide(1, $ratio);
  }

  $ratio: round($ratio * 10) * 0.1;

  @return $ratio;
}

@function has-value($val) {
  @if $val == null or $val == none {
    @return false;
  }
  @if type-of($val) == 'number' and strip-unit($val) == 0 {
    @return false;
  }
  @if type-of($val) == 'list' and length($val) == 0 {
    @return false;
  }
  @return true;
}

@function get-side($val, $side) {
  $length: length($val);

  @if $length == 1 {
    @return $val;
  }
  @if $length == 2 {
    @return map-get((top: nth($val, 1), bottom: nth($val, 1), left: nth($val, 2), right: nth($val, 2), ), $side);
  }
  @if $length == 3 {
    @return map-get((top: nth($val, 1), left: nth($val, 2), right: nth($val, 2), bottom: nth($val, 3), ), $side);
  }
  @if $length == 4 {
    @return map-get((top: nth($val, 1), right: nth($val, 2), bottom: nth($val, 3), left: nth($val, 4), ), $side);
  }
}

@function -zf-map-next-number($map, $number) {

  $next-number: null;

  @each $k, $v in $map {
    @if type-of($v) == 'number' and $v > $number and ($next-number == null or $v < $next-number) {
      $next-number: $v;
    }
  }

  @return $next-number;
}

@function _gamma($channel) {
  @if $channel < 0.03928 {
    @return $channel / 12.92;
  } @else {
    $c: ($channel + 0.055) / 1.055;
    @if function-exists("pow") {
      @return pow($c, 2.4);
    } @else {
      @return 0.56 * $c * $c * $c + 0.44 * $c * $c;
    }
  }
}

@function _contrast-ratio($color-1, $color-2) {
  $-local-lightness-1: _lightness($color-1) + 0.05;
  $-local-lightness-2: _lightness($color-2) + 0.05;

  @if $-local-lightness-1 > $-local-lightness-2 {
    @return $-local-lightness-1 / $-local-lightness-2;
  } @else {
    @return $-local-lightness-2 / $-local-lightness-1;
  }
}

@function luminance($color) {
  $rgb: (
    "r": red($color),
    "g": green($color),
    "b": blue($color)
  );

  @each $name, $value in $rgb {
    $value: if(divide($value, 255) < .04045, divide(divide($value, 255), 12.92), nth($_luminance-list, $value + 1));
    $rgb: map-merge($rgb, ($name: $value));
  }

  @return (map-get($rgb, "r") * .2126) + (map-get($rgb, "g") * .7152) + (map-get($rgb, "b") * .0722);
}

@function add($value1, $value2, $return-calc: true) {
  @if $value1 == null {
    @return $value2;
  }

  @if $value2 == null {
    @return $value1;
  }

  @if type-of($value1) == number and type-of($value2) == number and comparable($value1, $value2) {
    @return $value1 + $value2;
  }

  @return if($return-calc == true, calc(#{$value1} + #{$value2}), $value1 + unquote(" + ") + $value2);
}

@function -zf-breakpoints-less-than($key) {
  $list: ();
  $found-key: false;

  @each $name in $-zf-breakpoints-keys {
    @if ($name == $key) {
      $found-key: true;
    }
    @if not $found-key {
      $list: append($list, $name);
    }
  }
  @return $list;
}

@mixin center($width, $height: 0) {
  position: absolute;
  @if $height != 0 {
    left: calc(50% - (#{$width} * 0.5));
    top: calc(50% - (#{$height} * 0.5));
  } @else {
    left: calc(50% - (#{$width} * 0.5));
    top: calc(50% - (#{$width} * 0.5));
  }
}

@function _lightness($hex-color) {
  $-local-red-raw: red(rgba($hex-color, 1));
  $-local-green-raw: green(rgba($hex-color, 1));
  $-local-blue-raw: blue(rgba($hex-color, 1));

  $-local-red: _gamma($-local-red-raw / 255);
  $-local-green: _gamma($-local-green-raw / 255);
  $-local-blue: _gamma($-local-blue-raw / 255);

  @return $-local-red * 0.2126 + $-local-green * 0.7152 + $-local-blue * 0.0722;
}

@function map-loop($map, $func, $args...) {
  $_map: ();

  @each $key, $value in $map {
    // allow to pass the $key and $value of the map as an function argument
    $_args: ();
    @each $arg in $args {
      $_args: append($_args, if($arg == "$key", $key, if($arg == "$value", $value, $arg)));
    }

    $_map: map-merge($_map, ($key: call(get-function($func), $_args...)));
  }

  @return $_map;
}

@if $min and $max {
  $min-width: $min;
  $max-width: $max;

  @if not $is-number-lower and meta.type-of($min) == 'map' {
    $min-width: map.get($min, width);
  }

  @if not $is-number-upper and meta.type-of($max) == 'map' {
    $max-width: map.get($max, width);
  }

  @media (min-width: $min-width) and (max-width: $max-width) {
    @content;
  }
}

@mixin scrollbar-color-gray() {
  scrollbar-color: var(--#{$prefix}secondary-bg) transparent;

  &::-webkit-scrollbar-thumb {
    background-color: var(--#{$prefix}secondary-bg);
  }

  &::-webkit-scrollbar-track {
    background-color: transparent;
  }

  &::-webkit-scrollbar-corner {
    background-color: transparent;
  }
}

@function -zf-current-breakpoint($value: null, $default: null) {
  @if ($value != null) {
    @return $value;
  }
  @else if (variable-exists(-zf-size) and type-of($-zf-size) != 'number') and $-zf-size != null {
    @return $-zf-size;
  }
  @else {
    @return $default;
  }
}

@function -zf-bp-join(
  $min: 0,
  $max: 0,
  $min-name: 'min-width',
  $max-name: 'max-width'
) {
  @return zf-str-join(
    if($min and $min > 0, '(#{$min-name}: #{$min})', null),
    if($max and $max > 0, '(#{$max-name}: #{$max})', null),
    ' and ');
}

@each $_inuit-font-globals in
      $inuit-global-font-size
      $inuit-global-line-height {

  @if (type-of($_inuit-font-globals) == number) {

    @if (unit($_inuit-font-globals) != "px") {
      @error "`#{$_inuit-font-globals}` needs to be a pixel value.";
    }

  } @else {
    @error "`#{$_inuit-font-globals}` needs to be a number.";
  }

}

@function rgba-css-var($identifier, $target) {
  @if $identifier == "body" and $target == "bg" {
    @return rgba(var(--#{$prefix}#{$identifier}-bg-rgb), var(--#{$prefix}#{$target}-opacity));
  } @if $identifier == "body" and $target == "text" {
    @return rgba(var(--#{$prefix}#{$identifier}-color-rgb), var(--#{$prefix}#{$target}-opacity));
  } @else {
    @return rgba(var(--#{$prefix}#{$identifier}-rgb), var(--#{$prefix}#{$target}-opacity));
  }
}

@mixin button-size($padding-top, $padding-bottom, $padding-x, $font-size, $line-height) {
  --#{$prefix}btn-padding-top: #{$padding-top};
  --#{$prefix}btn-padding-bottom: #{$padding-bottom};
  --#{$prefix}btn-padding-x: #{$padding-x};
  @include rfs($font-size, --#{$prefix}btn-font-size);
  --#{$prefix}btn-line-height: #{$line-height};
}

@function _is-length($value) {
  @return type-of($value) != "null"
    and (
      str-slice($value + "", 1, 4) == "calc"
      or str-slice($value + "", 1, 3) == "var"
      or str-slice($value + "", 1, 3) == "env"
      or index(auto inherit initial 0, $value)
      or (type-of($value) == "number" and not(unitless($value)))
    );
}

@mixin button-size($padding-y, $padding-x, $font-size, $border-radius) {
  --#{$prefix}btn-padding-y: #{$padding-y};
  --#{$prefix}btn-padding-x: #{$padding-x};
  @include rfs($font-size, --#{$prefix}btn-font-size);
  --#{$prefix}btn-border-radius: #{$border-radius};
}

@for $i from 0 through get-column-count($breakpoints, $name) {
  @if is-smallest-breakpoint($name, $breakpoints) {
    .#{$prefix}--#{$name}\:col-span-#{$i} {
      @include -column-span($i);
    }
  } @else {
    @include breakpoint($name) {
      .#{$prefix}--#{$name}\:col-span-#{$i} {
        @include -column-span($i);
      }
    }
  }
}

@mixin -no-gutter {
  .#{$prefix}--no-gutter,
  .#{$prefix}--row.#{$prefix}--no-gutter [class*='#{$prefix}--col'] {
    padding-inline: 0;
  }

  .#{$prefix}--no-gutter--start,
  .#{$prefix}--row.#{$prefix}--no-gutter--start [class*='#{$prefix}--col'] {
    padding-inline-start: 0;
  }

  .#{$prefix}--no-gutter--end,
  .#{$prefix}--row.#{$prefix}--no-gutter--end [class*='#{$prefix}--col'] {
    padding-inline-end: 0;
  }
}

@each $constraint in ('min', 'max') {
  .#{$prefix}--layout-constraint--#{$group}__#{$constraint}-#{$step} {
    @include custom-property.declaration(
      'layout-#{$group}-#{$property}-#{$constraint}',
      custom-property.get-var(
        'layout-#{$group}-#{$property}-#{$step}',
        $value
      )
    );
  }
}

@each $aspect-ratio in $aspect-ratios {
  $width: list.nth($aspect-ratio, 1);
  $height: list.nth($aspect-ratio, 2);

  .#{$prefix}--aspect-ratio--#{$width}x#{$height}::before {
    padding-block-start: math.percentage(math.div($height, $width));
  }
}

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);

  @return (
    base: (),
    color: (
      ripple-color: m3-utils.color-with-opacity(
          map.get($system, on-surface), map.get($system, pressed-state-layer-opacity)),
    ),
    typography: (),
    density: (),
  );
}

@if not($has-presence) {
  &.is-visible .#{$prefix}--modal-container {
    transform: translate3d(0, 0, 0);
    transition: transform $duration-moderate-02 motion(entrance, expressive);
  }

  .#{$prefix}--modal-container {
    transform: translate3d(0, -24px, 0);
    transition: transform $duration-moderate-02 motion(exit, expressive);
  }
}

@include high-contrast-mode {
  .#{$prefix}--skeleton__text--ai,
  .#{$prefix}--skeleton__placeholder--ai,
  .#{$prefix}--skeleton__icon--ai {
    background: CanvasText;
  }

  .#{$prefix}--skeleton__text--ai::before,
  .#{$prefix}--skeleton__placeholder--ai::before,
  .#{$prefix}--skeleton__icon--ai::before {
    background: Canvas;
  }
}

@each $type, $colors in $types {
  $border: map.get($colors, 'border');
  $background: map.get($colors, 'background');
  $color: map.get($colors, 'color');

  .#{$prefix}--annotation--#{$type} {
    border-color: $border;
  }

  .#{$prefix}--annotation--#{$type} > .#{$prefix}--annotation__label {
    background-color: $background;
    color: $color;
  }
}

&::before,
    &::after {
      position: absolute;
      display: block;
      block-size: 1px;
      content: '';
      inline-size: calc(100% - $spacing-05 - $spacing-05);
      margin-inline-start: $spacing-05;
      transition: background motion(standard, productive) $duration-fast-02;

      @media screen and (prefers-reduced-motion: reduce) {
        transition: none;
      }
    }
